import { createApp, v, schema, validateRequest } from "skyguard-js";
const app = createApp();

const userSchema = schema({
  body: {  
    name: v.string({ minLength: 3 }),
    email: v.string().email(),
  }
});

app.post("/users", [validateRequest(userSchema)], (ctx) => {
  return { creado: true, user: ctx.body };
});

